#include <stdio.h>

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int R, C;
        char ch;

        // Read rows and columns
        scanf("%d %d", &R, &C);

        // Read character (with space before %c to ignore newline/space)
        scanf(" %c", &ch);

        // Print rectangle
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                printf("%c", ch);
            }
            printf("\n");
        }

        // Blank line after each test case
        printf("\n");
    }

    return 0;
}

code.Java:
import java.util.*;

public class Main {

    public static void sort(int[] arr) {
        int n = arr.length;
        for(int i = 0; i < n; i++) {
            for(int j = 0; j < n - 1; j++) {
                if(arr[j] > arr[j + 1]) {
                    int temp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = temp;
                }
            }       
        }
    }

    public static void main (String[] args) {

        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();

        int[] arr = new int[n];

        for(int i = 0; i < n; i++) {
            arr[i] = sc.nextInt();
        }

        sort(arr);

        for(int i = 0; i < n; i++) {
            System.out.print(arr[i] + " ");
        }
        System.out.println();
    }
}

